(function(g){function f(v){return typeof v==='number'&&Number.isFinite(v)}class Chart{constructor(canvas,cfg){this.canvas=canvas&&canvas.canvas?canvas.canvas:canvas;this.ctx=canvas&&canvas.getContext?canvas.getContext('2d'):this.canvas.getContext('2d');this._resize=this._resize.bind(this);this._cfg=null;this.updateConfig(cfg);window.addEventListener('resize',this._resize);this._resize()}updateConfig(cfg){this._cfg=cfg||{};this.type=this._cfg.type||'line';this.data=this._cfg.data||{labels:[],datasets:[]};this.options=this._cfg.options||{}}_resize(){if(!this.canvas||!this.ctx)return;const r=this.canvas.getBoundingClientRect();const d=window.devicePixelRatio||1;const w=Math.max(1,Math.round(r.width*d));const h=Math.max(1,Math.round(r.height*d));if(this.canvas.width!==w||this.canvas.height!==h){this.canvas.width=w;this.canvas.height=h}this.draw()}_ticks(min,max){const span=max-min||1;const raw=span/4;const base=Math.pow(10,Math.floor(Math.log10(raw)));const steps=[1,2,5,10];let step=base;for(const s of steps){if(base*s>=raw){step=base*s;break}}const start=Math.floor(min/step)*step;const arr=[];for(let t=start;t<=max+step;t+=step){arr.push(t)}return arr}draw(){const c=this.ctx,x=this.canvas;if(!c||!x)return;const labels=this.data.labels||[];const ds=(this.data.datasets&&this.data.datasets[0])||{data:[]};const vals=(ds.data||[]).map(Number).filter(f);c.clearRect(0,0,x.width,x.height);if(!labels.length||!vals.length)return;const pad={l:54,r:14,t:14,b:36};const w=x.width,h=x.height,pw=w-pad.l-pad.r,ph=h-pad.t-pad.b;const min=Math.min(...vals),max=Math.max(...vals);const yMin=min===max?min-1:min*0.95;const yMax=min===max?max+1:max*1.05;const yv=(v)=>pad.t+((yMax-v)/(yMax-yMin))*ph;const xv=(i)=>pad.l+(labels.length===1?pw/2:(i/(labels.length-1))*pw);c.strokeStyle='#cbd5e1';c.lineWidth=Math.max(1,(window.devicePixelRatio||1));c.beginPath();c.moveTo(pad.l,pad.t);c.lineTo(pad.l,pad.t+ph);c.lineTo(pad.l+pw,pad.t+ph);c.stroke();const ticks=this._ticks(yMin,yMax);c.fillStyle='#475569';c.font=`${12*(window.devicePixelRatio||1)}px sans-serif`;const tickFn=this.options?.scales?.y?.ticks?.callback;for(const t of ticks){const y=yv(t);c.strokeStyle='#e2e8f0';c.beginPath();c.moveTo(pad.l,y);c.lineTo(pad.l+pw,y);c.stroke();const txt=tickFn?String(tickFn(t)):String(Math.round(t*10)/10);c.fillText(txt,6*(window.devicePixelRatio||1),y+4*(window.devicePixelRatio||1))}c.fillStyle='#64748b';const step=Math.max(1,Math.ceil(labels.length/4));for(let i=0;i<labels.length;i+=step){const tx=xv(i);const txt=String(labels[i]);c.fillText(txt,tx-16*(window.devicePixelRatio||1),h-10*(window.devicePixelRatio||1))}if(this.type==='bar'){const bw=Math.max(8*(window.devicePixelRatio||1),pw/Math.max(labels.length,1)*0.6);c.fillStyle=ds.backgroundColor||'rgba(29,78,216,.25)';for(let i=0;i<vals.length;i++){const xx=xv(i)-bw/2;const yy=yv(vals[i]);c.fillRect(xx,yy,bw,pad.t+ph-yy)}}else{c.strokeStyle=ds.borderColor||'#1d4ed8';c.lineWidth=2*(window.devicePixelRatio||1);c.beginPath();for(let i=0;i<vals.length;i++){const xx=xv(i),yy=yv(vals[i]);if(i===0)c.moveTo(xx,yy);else c.lineTo(xx,yy)}c.stroke();c.fillStyle=ds.borderColor||'#1d4ed8';for(let i=0;i<vals.length;i++){const xx=xv(i),yy=yv(vals[i]);c.beginPath();c.arc(xx,yy,3*(window.devicePixelRatio||1),0,Math.PI*2);c.fill()}}}update(){this.draw()}destroy(){window.removeEventListener('resize',this._resize);if(this.ctx&&this.canvas)this.ctx.clearRect(0,0,this.canvas.width,this.canvas.height)}}g.Chart=Chart})(window);
